queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasBuildings ?child ; p:hasCollege_Campuses ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :College_Campuses } }
  FILTER(?nf = ?total)
}

