CHOICE scope {
  distributive: { SELECT ?name ?description WHERE {
  ?college_campuses_buildings a :College_Campuses_Buildings .
  ?buildings a :Buildings .
  ?college_campuses_buildings p:hasBuildings ?buildings .
  ?college_campuses a :College_Campuses .
  ?college_campuses_buildings p:hasCollege_Campuses ?college_campuses .
  ?college_campuses p:name ?name .
  ?buildings p:description ?description .
} }
  collective: { SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasBuildings ?child ; p:hasCollege_Campuses ?parent . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :College_Campuses } }
  FILTER(?nf = ?total)
} }
}

